$ErrorActionPreference = 'Stop'

function New-HarnessRecord {
    param(
        [string]$Name,
        [Nullable[int]]$Mode,
        [string]$Harness,
        [string]$Script,
        [string]$Target,
        [string]$Build,
        [string[]]$Tags
    )

    [PSCustomObject]@{
        Name = $Name
        Mode = $Mode
        Harness = $Harness
        Script = $Script
        Target = $Target
        Build = $Build
        Tags = $Tags
    }
}

