function Select-Smash64DSRegistryEntriesByName {
    param(
        [object[]]$Registry,
        [string[]]$Names
    )

    $entries = @()
    foreach ($name in $Names) {
        $record = $Registry | Where-Object { $_.Name -eq $name } | Select-Object -First 1
        if (-not $record) { throw "Registry entry '$name' was not found." }
        $entries += $record
    }
    return @($entries)
}

function Get-Smash64DSVerifyPlan {
    param(
        [ValidateSet('Full','Latest','LatestFast','BoundaryDirect','Boundary','Regression','RegressionFast','Smoke','SmokeFast','Fighter','Direct','MenuChain')]
        [string]$Profile = 'Full',
        [string[]]$Only,
        [string]$From
    )

    $registry = @(Get-Smash64DSHarnessRegistry)
    $plan = switch ($Profile) {
        'Full' { $registry }
        'Latest' {
            Select-Smash64DSRegistryEntriesByName $registry @(
                'runtime',
                'title',
                'battle_mariofox_stage_mplivehit_status_loop',
                'menu_chain_mariofox_stage_mplivehit_status_loop',
                'battle_playable'
            )
        }
        'LatestFast' {
            Select-Smash64DSRegistryEntriesByName $registry @(
                'title',
                'battle_mariofox_stage_mplivehit_status_loop',
                'menu_chain_mariofox_stage_mplivehit_status_loop'
