            )
        }
        'Smoke' { $registry | Where-Object { $_.Name -in @('runtime','opening_skip','title','vs_setup','vs_start_transition') } }
        'SmokeFast' { $registry | Where-Object { $_.Name -in @('title','vs_setup','vs_start_transition') } }
        'RegressionFast' {
            @(Get-Smash64DSVerifyPlan -Profile Regression) | Where-Object { $_.Name -ne 'runtime' }
        }
        'Fighter' { $registry | Where-Object { $_.Tags -contains 'fighter' } }
        'Direct' { $registry | Where-Object { $_.Tags -contains 'direct' } }
        'MenuChain' { $registry | Where-Object { $_.Tags -contains 'menu_chain' } }
    }

    if ($Only -and $Only.Count -gt 0) {
        $wanted = @($Only | ForEach-Object { $_.Trim() } | Where-Object { $_ })
        $plan = @($registry | Where-Object { $wanted -contains $_.Name })
        $missing = @($wanted | Where-Object { $name = $_; -not ($registry | Where-Object { $_.Name -eq $name }) })
        if ($missing.Count -gt 0) { throw "Unknown verifier registry name(s): $($missing -join ', ')" }
    } elseif ($From) {
        $index = -1
        for ($i = 0; $i -lt $plan.Count; $i++) {
            if ($plan[$i].Name -eq $From) { $index = $i; break }
        }
        if ($index -lt 0) { throw "Registry entry '$From' is not in profile '$Profile'." }
        $plan = @($plan[$index..($plan.Count - 1)])
    }

    return @($plan)
